import React from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* Card */}
      <div style={styles.card}>

        {/* Logo */}
        <h1 style={styles.logo}>DocBook</h1>

        <h2 style={styles.title}>Welcome</h2>

        <p style={styles.subtitle}>
          Book doctor appointments easily and manage your health.
        </p>

        {/* Buttons */}
        <button
          style={styles.loginBtn}
          onClick={() => navigate("/login")}
        >
          Login
        </button>

        <button
          style={styles.registerBtn}
          onClick={() => navigate("/register")}
        >
          Register
        </button>

      </div>

    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "linear-gradient(135deg, #2563EB, #1E40AF)", // navbar theme
    fontFamily: "Segoe UI, sans-serif",
  },

  card: {
    backgroundColor: "white",
    padding: "40px",
    borderRadius: "12px",
    width: "320px",
    textAlign: "center",
    boxShadow: "0 10px 30px rgba(0,0,0,0.2)",
  },

  logo: {
    color: "#2563EB",
    marginBottom: "10px",
  },

  title: {
    marginBottom: "10px",
  },

  subtitle: {
    fontSize: "14px",
    color: "#666",
    marginBottom: "25px",
  },

  loginBtn: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    borderRadius: "6px",
    marginBottom: "10px",
    cursor: "pointer",
    fontWeight: "600",
  },

  registerBtn: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#10B981",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    fontWeight: "600",
  },
};
